const Icon = ({ type, color, width, height, fill }: IconProps) => {
  switch (type) {
    case "football":
      return <FootballIcon />;
    case "gym":
      return <GymIcon />;
    case "swimming":
      return <Swimming />;
    case "spa":
      return <Spa />;
    case "instagram":
      return <Instagram />;
    case "mail":
      return <Mail />;
    case "phone":
      return <Phone />;
    case "menu":
      return <Menu />;
    case "dropangle":
      return <DropAngle />;
    case "xicon":
      return <XIcon />;
    case "whatsapp":
      return <Whatsapp />;
    case "leftangle":
      return <LeftAngle />
    case "rightangle":
      return <RightAngle />
  }
};

export default Icon;
